ps.pstext:
if !IsFeatureImplemented(FEAT_LRCPC3) then EndOfDecode(Decode_UNDEF); end;
let ispair : boolean = TRUE;
let wback : boolean = opc2[0] == '0';

let t : integer{} = UInt(Rt);
let t2 : integer{} = UInt(Rt2);
let n : integer{} = UInt(Rn);
let scale : integer{} = 2 + UInt(size[0]);
let datasize : integer{} = 8 << scale;
let offset : integer = if opc2[0] == '0' then -1 * (2 << scale) else 0;
let acqrel : boolean = FALSE;
let tagchecked : boolean = wback || n != 31;

var rt_unknown : boolean = FALSE;

if wback && (t == n || t2 == n) && n != 31 then
    let c : Constraint = ConstrainUnpredictable(Unpredictable_WBOVERLAPST);
    assert c IN {Constraint_NONE, Constraint_UNKNOWN, Constraint_UNDEF, Constraint_NOP};
    case c of
        when Constraint_NONE =>    rt_unknown = FALSE;   // value stored is pre-writeback
        when Constraint_UNKNOWN => rt_unknown = TRUE;    // value stored is UNKNOWN
        when Constraint_UNDEF =>   EndOfDecode(Decode_UNDEF);
        when Constraint_NOP =>     EndOfDecode(Decode_NOP);
    end;
end;

var address : bits(64);
var data1 : bits(datasize);
var data2 : bits(datasize);
let dbytes : integer{} = datasize DIV 8;
var accdesc : AccessDescriptor = CreateAccDescAcqRel(MemOp_STORE, tagchecked,
                                                     ispair, acqrel, t, t2);

if n == 31 then
    CheckSPAlignment();
    address = SP{64}();
else
    address = X{64}(n);
end;

address = AddressAdd(address, offset, accdesc);

if rt_unknown && t == n then
    data1 = ARBITRARY : bits(datasize);
else
    data1 = X{datasize}(t);
end;
if rt_unknown && t2 == n then
    data2 = ARBITRARY : bits(datasize);
else
    data2 = X{datasize}(t2);
end;

var full_data : bits(2*datasize);
if BigEndian(accdesc.acctype) then
    full_data = data1::data2;
else
    full_data = data2::data1;
end;
accdesc.highestaddressfirst = offset < 0;
Mem{2*datasize}(address, accdesc) = full_data;

if wback then
    if n == 31 then
        SP{64}() = address;
    else
        X{64}(n) = address;
    end;
end;
